import { stat } from 'node:fs/promises';
import { sep } from 'node:path';
export async function convertResourceToArcFormat(resource, functionPath, transpiled) {
    if (!resource.src) {
        throw Error('Missing `resource.src` property');
    }
    // Get stats from file
    const stats = await stat(functionPath);
    // Convert resource.src to arc file path format
    const srcPath = resource.src?.split(sep).join('/');
    const entryDir = stats.isFile() ? srcPath.substring(0, srcPath.lastIndexOf('/')) : srcPath;
    functionPath = transpiled ? `${entryDir}/.build/function-${resource.name}` : entryDir;
    return `@app
hydrate-function

@events
${resource.name}
  src ${functionPath}
`;
}
